INSERT INTO birthday_messages (content, is_active, type) VALUES
('Prezado(a) cliente, neste dia especial, renovamos nossos votos de estima e consideração. Que seu aniversário seja o início de um ano repleto de realizações pessoais e profissionais.', true, 'profissional'),
('Parabéns pelo seu dia! Que a sabedoria e a serenidade guiem seus passos neste novo ciclo. Felicidades de toda a nossa equipe jurídica.', true, 'profissional'),
('Celebrar o seu aniversário é celebrar uma parceria de confiança. Desejamos muita saúde, prosperidade e paz.', true, 'profissional'),
('Mais um ano de vida, mais um ano de conquistas! Que seus direitos sejam sempre preservados e seus sonhos realizados.', true, 'profissional'),
('Feliz aniversário! É um privilégio atuar na defesa dos seus interesses. Que a vida lhe retribua com muita alegria e tranquilidade.', true, 'profissional');
INSERT INTO birthday_messages (content, is_active, type) VALUES
('Hoje o dia é todo seu! Nossa equipe lhe deseja um feliz aniversário. Que a paz e a alegria sejam constantes em sua jornada.', true, 'afetuosa'),
('Um brinde a você! Que a vida continue lhe presenteando com momentos inesquecíveis. Receba o abraço afetuoso de toda a nossa equipe neste dia tão especial.', true, 'afetuosa'),
('Hoje celebramos a sua vida! Que este novo ciclo seja de muita paz, saúde e felicidade. É uma honra tê-lo(a) conosco.', true, 'afetuosa'),
('Feliz aniversário! Que a vida continue lhe presenteando com momentos inesquecíveis ao lado de quem você ama.', true, 'afetuosa'),
('Hoje é dia de celebrar você! Agradecemos por nos permitir fazer parte da sua história. Um feliz e abençoado aniversário.', true, 'afetuosa');
